+        _warehouseState.OnChange += HandleWarehouseChanged;
+    }
+
+    /// <summary>Simulates a database query returning a random low-stock count.</summary>
+    public Task<int> GetLowStockCountAsync(string warehouseId)
+    {
+        return Task.FromResult(_rng.Next(0, 16));
+    }
+
+    /// <summary>
+    /// Increment the subscriber count and start polling if this is the first subscriber.
+    /// </summary>
+    public void StartPolling()
+    {
+        _subscriberCount++;
+        if (_subscriberCount == 1)
+            BeginPollingLoop();
+    }
+
+    /// <summary>
+    /// Decrement the subscriber count and stop polling when no subscribers remain.
+    /// </summary>
+    public void StopPolling()
+    {
+        _subscriberCount = Math.Max(0, _subscriberCount - 1);
+        if (_subscriberCount == 0)
+            CancelPollingLoop();
+    }
+
+    public void Dispose()
+    {
+        _warehouseState.OnChange -= HandleWarehouseChanged;
+        CancelPollingLoop();
+    }
+
+    private void HandleWarehouseChanged()
+    {
+        // Immediately refresh when the warehouse changes so every
+        // subscriber sees up-to-date data without waiting for the next tick.
+        _ = PollOnceAsync();
+    }
+
+    private void BeginPollingLoop()
+    {
+        CancelPollingLoop();
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        _ = RunPollingLoopAsync(_cts.Token);
+    }
+
+    private void CancelPollingLoop()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+        _timer?.Dispose();
+        _timer = null;
+    }
+
+    private async Task RunPollingLoopAsync(CancellationToken ct)
+    {
+        // Fire immediately on start, then every 10 seconds.
+        await PollOnceAsync();
+
+        while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
+        {
+            await PollOnceAsync();
+        }
+    }
+
+    private async Task PollOnceAsync()
+    {
+        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
+        LatestLowStockCount = count;
+        OnAlertCountChanged?.Invoke();
+    }
+}
